        default: 'Toastboy FC',
        template: '%s | Toastboy FC',
    },
    description: "Toastboy FC: five-a-side footy on Tuesdays at Kelsey Kerridge, Cambridge",
    icons: {
        icon: "/favicon.ico",
    },
};

export default async function RootLayout({
    children,
}: {
    children: React.ReactNode;
}) {
    const user = await getCurrentUser();
    const devMode = !(process.env.NODE_ENV === 'production' && !process.env.CI);

    return (
        <html lang="en" {...mantineHtmlProps}>
            <head>
                <ColorSchemeScript defaultColorScheme="light" />
            </head>
            <body>
                <MantineProvider defaultColorScheme="light">
                    <Notifications />
                    {/* <DebugBreakpoints /> */}
                    <DebugFontSizes targets={[{ label: 'PlayerLink', selector: '[class*="PlayerLink_link"]' }]} />
                    <CustomAppShell user={user} devMode={devMode}>
                        {children}
                    </CustomAppShell>
                </MantineProvider>
            </body>
        </html>
    );
}

